CREATE TABLE IF NOT EXISTS "PROGRAMAS_EDUCACION_INICIAL" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CODIGO" VARCHAR(200) NOT NULL UNIQUE,
    "GRADO" VARCHAR(20) NOT NULL,
    "ASIGNATURA_VISIBLE" VARCHAR(200) NOT NULL,
    "ASIGNATURA_VISIBLE_NORMALIZADA" VARCHAR(200) NOT NULL,
    "AMBITO" VARCHAR(200) NOT NULL,
    "AMBITO_NORMALIZADO" VARCHAR(200) NOT NULL,
    "NUCLEO" VARCHAR(200) NOT NULL,
    "NUCLEO_NORMALIZADO" VARCHAR(200) NOT NULL,
    "TOTAL_OAS" INTEGER,
    "CONTENIDO_JSON" JSONB NOT NULL,
    "ACTIVO" BOOLEAN NOT NULL DEFAULT TRUE,
    "FECHA_CREACION" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "FECHA_ACTUALIZACION" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS "PROGRAMAS_EDUCACION_INICIAL_OAS" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "PROGRAMA_ID" BIGINT NOT NULL REFERENCES "PROGRAMAS_EDUCACION_INICIAL" ("ID") ON DELETE CASCADE,
    "ORDEN" INTEGER NOT NULL,
    "CODIGO" VARCHAR(30) NOT NULL,
    "DESCRIPCION" TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS "PROGRAMAS_EDUCACION_INICIAL_OA_INDICADORES" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "OA_ID" BIGINT NOT NULL REFERENCES "PROGRAMAS_EDUCACION_INICIAL_OAS" ("ID") ON DELETE CASCADE,
    "ORDEN" INTEGER NOT NULL,
    "DESCRIPCION" TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS "PROGRAMAS_EDUCACION_INICIAL_OA_ACTIVIDADES" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "OA_ID" BIGINT NOT NULL REFERENCES "PROGRAMAS_EDUCACION_INICIAL_OAS" ("ID") ON DELETE CASCADE,
    "ORDEN" INTEGER NOT NULL,
    "NUMERO" INTEGER,
    "DESCRIPCION" TEXT NOT NULL
);

CREATE UNIQUE INDEX IF NOT EXISTS "UK_PROG_ED_INICIAL_SCOPE"
    ON "PROGRAMAS_EDUCACION_INICIAL" ("GRADO", "ASIGNATURA_VISIBLE_NORMALIZADA", "AMBITO_NORMALIZADO", "NUCLEO_NORMALIZADO");

CREATE INDEX IF NOT EXISTS "IDX_PROG_ED_INICIAL_SCOPE"
    ON "PROGRAMAS_EDUCACION_INICIAL" ("GRADO", "ASIGNATURA_VISIBLE_NORMALIZADA", "AMBITO_NORMALIZADO", "NUCLEO_NORMALIZADO");

CREATE INDEX IF NOT EXISTS "IDX_PROG_ED_INICIAL_OAS_PROGRAMA"
    ON "PROGRAMAS_EDUCACION_INICIAL_OAS" ("PROGRAMA_ID", "ORDEN");

CREATE INDEX IF NOT EXISTS "IDX_PROG_ED_INICIAL_INDICADORES_OA"
    ON "PROGRAMAS_EDUCACION_INICIAL_OA_INDICADORES" ("OA_ID", "ORDEN");

CREATE INDEX IF NOT EXISTS "IDX_PROG_ED_INICIAL_ACTIVIDADES_OA"
    ON "PROGRAMAS_EDUCACION_INICIAL_OA_ACTIVIDADES" ("OA_ID", "ORDEN");
